var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"토…… 토할 거 같아…….","JPN":"は……吐きそう……","ENG":"I... I think I'm going to throw up...","TWN":"我……我要吐了……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이딴 게 공간 도약……? 차라리 죽고 말지, 우욱……!","JPN":"これが空間跳躍……？　死ぬ方がマシだよ、げえっ……！","ENG":"This is what the space jump is...? I'd rather die, urgh...!","TWN":"這就是空間跳躍嗎……？還不如乾脆去死，噁噁……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……더 이상 뭔가 시켰다간 차라리 뇌를 리셋시켜 버릴 테다.","JPN":"……これ以上私に何かをやらせる気なら、いっそこの頭脳をリセットしてやる。","ENG":"…If you give me one more task, I will reset my brain.","TWN":"……再叫我做什麼的話，大腦就要初始化了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"개인적인 고충은 잠시 참길 바란다!","JPN":"個人的な苦情は少し我慢しろ！","ENG":"Withhold all personal conflicts for now!","TWN":"個人的難處希望大家都先克服一下！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전 대원, 상황을 보고하도록!","JPN":"全隊員、状況を報告しろ！","ENG":"All members, report!","TWN":"全體隊員，報告情況！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 전방에 적성 개체 반응 확인! 2종에 상당하는 녀석들뿐이야!","JPN":"おばさん！　前方に敵性個体の反応を確認！　2種に相当する奴らばかりよ！","ENG":"Maria! Hostiles detected in the front! They're all at least Category 2s!","TWN":"大嬸！前方感應到敵人個體反應！是相當於2類的傢伙！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"휘유, 이거 참 산 넘어 산인데?","JPN":"はあ、次から次と！","ENG":"*Whistle* It's always one thing after another.","TWN":"呼，這可真是困難重重啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어서 문 열어! 대장이 저 아래 있을 거라고!","JPN":"早くドアを開けろ！　きっと隊長はあそこにいる！","ENG":"Open up! Cap's down there!","TWN":"喂！快點開門！隊長在那下邊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"얌전히 있어. 혼자 뛰어들다간 순식간에 다진 고기 꼴이 될 걸.","JPN":"大人しくここで待ちな。一人で飛び込んでもひき肉になって終わるだけだから。","ENG":"Stay still. You'll become ground meat if you rush out on your own.","TWN":"好好待著！這個高度掉下去，你想變成肉醬嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"현재 탑승한 전투원 전원, 강하 태세로 대기 중입니다.","JPN":"現在搭乗している戦闘員は全員、降下態勢で待機中です。","ENG":"All combatants onboard on standby, ready to drop.","TWN":"目前在艦船上的全體戰鬥人員，請隨時聽候命令。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 지시를.","JPN":"司令官、指示を。","ENG":"Awaiting your order, Commander.","TWN":"司令官，請下達指示。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"회장님, 잠시 힘을 빌릴 수 있겠습니까?","JPN":"会長、一瞬力をお借りしてもよろしいでしょうか？","ENG":"Miss Shin, would you lend me a hand for a moment?","TWN":"會長，可以暫時借助一下你的力量嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……아하.","JPN":"……なるほど。","ENG":"...Aha.","TWN":"……啊啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 물론이죠, 안토노프 사령관님. 여기가 바로 전환점이 될 테니까요.","JPN":"はい、もちろんです、アントノフ司令官。ここから巻き返しの時になるでしょうから。","ENG":"Of course, Commander Antonov. This will be the turning point.","TWN":"嗯，當然可以，安東諾夫司令官。從這裡開始就是轉捩點了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전환점. 지금 상황에서 적절한 표현이군요.","JPN":"巻き返しの時。この状況にピッタリの表現です。","ENG":"Turning point. That's a nice way to put it.","TWN":"轉捩點。這個措辭很適合現在的情況呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전 승조원 전투 태세로!","JPN":"全乗組員、戦闘態勢！","ENG":"All hands, get ready for battle!","TWN":"艦上全體人員，維持戰鬥之姿！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"대기 중인 전투원들은 즉시 강하하도록!","JPN":"待機中の戦闘員たちは直ちに降下せよ！","ENG":"All combatants, you may drop now!","TWN":"待命中的戰鬥人員，現在開始登陸！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 사람은…….","JPN":"あの人は……","ENG":"That person...","TWN":"那個人是……"},"stage":{"bg":"MAINSTREAM_803","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대령님! 무사했구나!","JPN":"大佐！　無事だったんだ！","ENG":"Colonel! You made it!","TWN":"上校！你沒事啊！"},"stage":{"bg":"MAINSTREAM_803","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"다시 보니 반가운데, 용병 아가씨.","JPN":"もう一度会えて嬉しいよ、傭兵のお嬢ちゃん。","ENG":"It's nice to see you again, Miss Mercenary.","TWN":"很高興又見面了，傭兵小姐。"},"stage":{"bg":"MAINSTREAM_803","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"우리 없는 동안 친구들은 많이 사귀었나?","JPN":"俺たちがいない間に友達はたくさんできたか？","ENG":"Made a lot of friends while we were gone?","TWN":"我們不在的這段時間，你又交了很多朋友啊？"},"stage":{"bg":"MAINSTREAM_803","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흐음…… 뭔가 했더니, 결국 패잔병들이었군.","JPN":"ふむ……何かと思えば、結局敗残兵だったか。","ENG":"Well, well, well... If it isn't the pathetic remnants.","TWN":"好吧……我還以為是誰，原來是你們這群殘兵敗將。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"한 번 도망쳤던 자들이 다시 가세한다고 해서 전세가 뒤집힐 것 같나?","JPN":"一度逃げていった貴様らがもう一度加勢したところで、形勢を逆転できると思うか？","ENG":"Do you think cowards like yourselves could change the tides of war?","TWN":"逃過一劫的懦夫還想要扭轉戰局嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하, 그 말도 일리는 있어. 멋쟁이 씨.","JPN":"はは、確かにそれもそうだな、イケメンさん。","ENG":"Ha ha. Fair point, Handsome.","TWN":"哈哈，你說得也有道理，帥哥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하지만 말이야, 우리에겐 그쪽 덕분에 손가락 빨고 기다리던 용병들이 굉장히 많거든.","JPN":"でもよ、こっちにはあんたのおかげで、待ちくたびれている傭兵がたくさんいるんだ。","ENG":"But you know what? We have an army of mercenaries who are eager to join because of you.","TWN":"不過，托你的福，我們有很多蓄勢待發的傭兵呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……용병이라고?","JPN":"……傭兵だと？","ENG":"...Mercenaries?","TWN":"……傭兵？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"함교, 갑판에 도착했다.","JPN":"艦橋、甲板に到着した。","ENG":"Bridge, we arrived at the destination.","TWN":"艦橋，我們已經抵達甲板。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"공간 좌표 포착 완료. 상황 공유 바란다.","JPN":"空間座標の捕捉を完了。状況を教えてくれ。","ENG":"Space coordinates detected. Copy, over.","TWN":"空間座標捕捉完畢，請分享情況。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"구조 분석은 끝났어요, 안토노프 사령관님. 언제든 시작해 주세요.","JPN":"構造分析は終わりました、アントノフ司令官。いつでも始めてください。","ENG":"The structural analysis is done, Commander Antonov. You may start whenever you please.","TWN":"結構分析結束了，安東諾夫司令官。請隨時開始。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……귀찮은 할멈 같으니.","JPN":"……面倒くさい婆さんだ。","ENG":"...Pesky old woman.","TWN":"……真是囉嗦的老太婆。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"쿼드 엔진 최대 출력 도달. 동력 공급도 문제 없다.","JPN":"クワッドエンジンが最大出力に到達。動力の供給にも異常なし。","ENG":"Quad Engines reached maximum output. Power issues all clear.","TWN":"四驅引擎已經達到最大輸出，動力供應也沒問題。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"실전에서 이런 무모한 짓을 하게 될 줄은 몰랐지만……. 이 방법뿐이군.","JPN":"実戦でこんな無謀なことをやることになるとは思わなかったが……これしかない。","ENG":"I never thought I would do such a reckless act... But it seems that this might be the only way.","TWN":"沒想到會在實戰中做出這種魯莽的事……但只有這個辦法了。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"가르강튀아, 전개!","JPN":"ガルガンティア、展開！","ENG":"Garguantia, activate!","TWN":"加爾剛迪亞，啟動！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START2"},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 안 돼……. 가르강튀아의 신호가 점점 늘어나고 있잖아?","JPN":"嘘……ガルガンティア信号がどんどん増幅してる？","ENG":"No way... The Garguantia's signal is amplifying!","TWN":"不可能……加爾剛迪亞的訊號正在逐漸增強？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말 알파트릭스 회장 혼자서 생산이 가능하다고? 다른 것도 아니고 시공가속기를?","JPN":"まさか本当にアルファトリックス会長一人で生産できるの？　あの時空加速器を？","ENG":"Is the Alphatrix's President really able to produce all that alone? A time-space accelerator, out of all things?","TWN":"阿爾法崔克斯會長連這個都能夠獨自生產？又不是別的東西，那可是時空加速器啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……아뇨. 첩보로 확인한 것보다 압도적인 위력입니다.","JPN":"……いいえ。確認している情報よりも圧倒的な威力です。","ENG":"...No. It exceeds the output of what we've received from our intel.","TWN":"……不，威力情報中說的還厲害。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"오비탈 베이스의 시설로 백업한다고 해도, 저 상태를 오래 지속하진 못할 거예요.","JPN":"オービタルベースの施設でバックアップをしても、あの状態を長く維持することは無理でしょう。","ENG":"Even with the backup from the facilities at Orbital Base, she won't be able to last long in that form.","TWN":"不過就算是借助軌道基地的設施進行了備份，這個狀態也無法持續太久。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"사령관님, 제가 도와 드릴 수 있는 영역은 여기까지예요!","JPN":"司令官、私が手伝える領域はここまでです！","ENG":"This is as far as I can go, Commander!","TWN":"司令官，我能幫的忙就到這裡了！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"고맙습니다, 회장님.","JPN":"ありがとうございます、会長。","ENG":"You have my gratitude, Miss Shin.","TWN":"不勝感激，會長。"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"전 태스크포스에 마리아 안토노프가 전달한다!","JPN":"全タスクフォースにマリア・アントノフが告げる！","ENG":"This is Maria Antonov speaking to all TASKFORCEs!","TWN":"瑪麗亞·安東諾夫現特別通知全體特遣勢力！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"현재 통신이 전달된 좌표를 기준으로 작전 코드, 프리덤 스트라이크가 발동되었다!","JPN":"現在通信された座標を元に、作戦コード「フリーダム・ストライク」が発動された！","ENG":"Operation code Freedom Strike has been activated, from the delivered target coordinates!","TWN":"以目前通訊傳達的座標為基準，作戰代號：自由之擊，已啟動！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"적은 도플갱어 타입 침식체 다수!","JPN":"敵は多数のドッペルゲンガータイプの侵食体！","ENG":"Our enemies are multiple Doppelganger-type C.O.s!","TWN":"我們的敵人是大量小型二重身類型侵蝕體！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"비상 대기로 인해 이터니움 수급이 어려웠다면, 이번 작전에 반드시 참가하도록!","JPN":"非常待機によってエタニウムをあまり受給できなかった者は、今回の作戦には必ず参加するように！","ENG":"For those who had trouble collecting Eternium due to emergency standby, now is your chance to take part!","TWN":"如果因緊急待命而極需永恆之金的特遣勢力，請務必不要錯過這次作戰！"},"stage":{"bg":"MS_905","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어리석은 짓을…….","JPN":"愚かなことを……","ENG":"A foolish act...","TWN":"真是愚蠢……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"각개격파당하던 너희 이방인들이 저런 부탁에 응할 것 같나?","JPN":"各個撃破された貴様ら異邦人が、そんな要請に応じると思うか？","ENG":"Do you think outsiders like you will accept such a request, when you've been getting crushed this whole time?","TWN":"你認為他們會為了你們這群喪家犬接受這樣的請求嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하, 그거야 두고 보면 알겠지.","JPN":"はは、それは見ていればわかるだろう。","ENG":"Ha ha, we'll see about that.","TWN":"哈哈，那我們就走著瞧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>차원 도약 완료. 고준위 침식파가 감지됩니다.</color>","JPN":"<color=#ffd34c>次元跳躍完了。高レベルの侵食波が検知されます。</color>","ENG":"<color=#ffd34c>Dimension jump complete. High-level Corruption ray detected.</color>","TWN":"<color=#ffd34c>次元跳躍完畢，感應到高侵蝕波。</color>"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>…긴급한 채굴 작전으로, 직원 여러분께서는 안전에 유의하여….</color>","JPN":"<color=#ffd34c>……緊急な採掘作戦であるため、職員の皆様は安全に注意しつつ……</color>","ENG":"<color=#ffd34c>...Due to urgent mining operation, all employees are advised safety...</color>","TWN":"<color=#ffd34c>……正在進行緊急開採作戰，各位員工請注意安全……</color>"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저건…… 그레이스가 남긴 무구인가?","JPN":"あの剣は……グレースが残した武器なのか？","ENG":"That sword... Is it the armament that Grace left behind?","TWN":"那把劍是……葛瑞絲留下的武器嗎？"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠, 부름에 응해 도착했다.","JPN":"ゾディアックナイツ、呼び出しを受けて参上した。","ENG":"Zodiac Knights, at your service.","TWN":"十二宮騎士團，奉召抵達。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 저들은……!","JPN":"団長、あの者たちは……！","ENG":"Captain, those are...!","TWN":"團長，那些人是……！"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L48_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨! 뒷처리로 한창 바쁜 마당에 어디로 가신 겁니까!","JPN":"お嬢様！　後始末でこんなに忙しいときにどこに行かれてたんですか？","ENG":"My Lady! Where are you? We have a ton of work to do!","TWN":"小姐！這裡正忙著收拾殘局呢，您去哪裡了？"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대통령 각하를 모셨으면 우리 일은 끝난 거예요, 페리어.","JPN":"大統領閣下を連れだせたので、私たちの仕事は終わったんですよ、フェリエー。","ENG":"We have escorted the President, so our work is done, Ferrier.","TWN":"既然總統已經救回來了，我們的工作就結束了，佩里。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"장차 상대하게 될 적들의 전력을 가늠할 기회로 제격 아닌가요?","JPN":"今後相手にしていくであろう敵の戦力を知る良い機会ではありませんか？","ENG":"Wouldn't it be a great opportunity to assess the enemies that we will be facing in the future?","TWN":"這正是評估將來要對付的敵人戰鬥力的大好機會，不是嗎？"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"행정 업무가 싫어서 도망치셨다고 솔직히 말씀하셔도─","JPN":"事務が嫌だから逃げたって正直に言ってくださっても─","ENG":"Just be honest and say that you didn't want to deal with the paperwork─","TWN":"不喜歡行政作業，您可以實話實說，沒必要——"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전투 환경에 적응할 수 있도록 신형 리액터를 지급하겠습니다!","JPN":"戦闘環境に適応できるよう、新型のリアクターを支給いたします！","ENG":"We will supply you with new reactors to help you familiarize yourself with the battle environment!","TWN":"為了協助適應戰鬥環境，我們可以給大家提供新型電抗器！"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"단시간만 버틸 수 있는 사양이니 신중하게 사용해 주세요!","JPN":"短時間しか耐えられない仕様ですから、慎重にお使いくださいね！","ENG":"It won't last long, so use it wisely!","TWN":"不過只能堅持很短的時間，所以一定要謹慎使用！"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 무사하셨군요.","JPN":"お嬢様、ご無事でしたか。","ENG":"Miss Jia! You're safe.","TWN":"小姐，你還活著啊！"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"오비탈 베이스 소식을 듣고 걱정했습니다.","JPN":"オービタルベースの知らせを聞いて、心配しておりました。","ENG":"I was worried when I heard the news about Orbital Base.","TWN":"聽說軌道基地的消息後，我一直很擔心。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"미안해요, 이진 언니. 한동안 연락하기 어려운 상황이었거든요.","JPN":"ごめんなさい、ホノカさん。しばらく連絡が取れない環境にいたので。","ENG":"I'm sorry, Jin. I was in a rather difficult situation to make contacts.","TWN":"對不起，李珍姐。這麼長時間都沒能聯繫你。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아뇨. 괜찮습니다.","JPN":"……いいえ、大丈夫です。","ENG":"...No, it's okay.","TWN":"……不，沒關係。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"관리국의 비상 대기 조치로 불만이 쌓인 태스크포스들이 전부 해당 좌표로 진입 중입니다.","JPN":"管理局の非常待機措置によって不満を募らせたタスクフォースたちが全員該当の座標に侵入中です。","ENG":"All TASKFORCEs frustrated by the Administration's emergency standby orders are entering the designated coordinates.","TWN":"對管理局的緊急待命指令心懷不滿的特遣勢力，現在都在朝著這個座標跳躍。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저도 곧 가겠습니다. 그 때까지 무사하시길.","JPN":"私もすぐに行きます。それまでご無事で。","ENG":"I will be joining soon as well. Stay safe until then.","TWN":"我也會馬上趕過去。在那之前，請你多保重。"},"stage":{"bg":"MS_1104","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_A","text":{"KOREA":"적은 도플갱어 타입 침식체다! 실력 없는 놈들은 후방에서 지원해!","JPN":"敵はドッペルゲンガー侵食体だ！　腕に自信のない奴は後方から支援しろ！","ENG":"The enemies are Doppelganger-type C.O.s! If you're not confident with your shooting skills, fall back and support!","TWN":"是小型二重身類型型侵蝕體！實力不行的傢伙待在後方支援！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"그 갑옷 입은 놈들이 틀림없는 거겠지? 죽은 친구 놈 대신 한 발 박아주겠어!","JPN":"この鎧姿の奴らで間違いないんだろうな？　死んだ友達の代わりに一発撃ち込んでやる！","ENG":"It must be those armored ones! I'll shoot a bullet through their heads for killing my friend!","TWN":"是那些穿著鎧甲的傢伙沒錯吧？我要替死去的朋友痛扁他們！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"남들 휴업하게 만들고 발 뻗고 살 수 있을 줄 알았냐? 우리도 이판사판이야!","JPN":"俺たちを休業にさせといて無事でいられると思ったか？　こっちも一か八かだ！","ENG":"You thought you could get away with ruining other people's businesses? We have nothing to lose!","TWN":"別以為毀掉別人的生意之後還可以大搖大擺地活著！我們玩命可是在行的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"알렌 경, 적의 증원입니다!","JPN":"バーミンガム卿、敵の増援です！","ENG":"Sir Allen, more enemies are approaching!","TWN":"艾倫大人，敵人出現了增援！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그래. 이대로는 저들의 세계로 진출은 고사하고, 늑대마저 놓칠 수 있다.","JPN":"ああ、このままでは奴らの世界に侵入どころか、狼すら逃してしまうかもしれん。","ENG":"Yes. If the situation continues, we might lose the Wolf, let alone advancing into their world.","TWN":"照這樣下去，別說進軍他們的世界，連狼都可能捉不到。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"늑대는 전하께 맡긴다.","JPN":"狼は殿下に任せる。","ENG":"We will leave the Wolf up to His Highness.","TWN":"把狼交給殿下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"품위를 버려도 좋다! 적의 증원이 전하의 발을 묶는 일만큼은 없게 하도록!","JPN":"品位など捨てても良い！　敵の増援が殿下の邪魔をすることだけは防げ！","ENG":"Discard your dignity! Do not let the enemy get in the way of His Highness, no matter what!","TWN":"哪怕拋棄尊嚴也好！不能讓敵人的增援絆住殿下的手腳！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……예! 명심하겠습니다!","JPN":"……はい！　承知いたしました！","ENG":"...Yes, sir! Understood!","TWN":"……是！遵命！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};